script:
BURL=$(az keyvault secret show --vault-name SDN-YooVault --name edge-bridge-url --query value -o tsv); BTOK=$(az keyvault secret show --vault-name SDN-YooVault --name edge-bridge-token --query value -o tsv); echo 'url:'"$BURL"; echo 'tok-len:'"${#BTOK}"; echo; echo '=== GET /  ==='; curl -s -w '
  HTTP=%{http_code}
' -H "Authorization: Bearer $BTOK" "$BURL/" 2>&1 | head -30; echo; echo '=== GET /health ==='; curl -s -w '
  HTTP=%{http_code}
' -H "Authorization: Bearer $BTOK" "$BURL/health" 2>&1 | head -10; echo; echo '=== GET /openapi.json or /docs ==='; for path in /openapi.json /docs /api /api/health /api/spec /version; do echo "path=$path"; curl -s -o /tmp/eb-$$ -w '  HTTP=%{http_code}
' -H "Authorization: Bearer $BTOK" "$BURL$path"; head -c 200 /tmp/eb-$$ 2>/dev/null; echo; rm -f /tmp/eb-$$; done
